+func normalizeState(value string) (string, error) {
+	value = strings.TrimSpace(strings.ToLower(value))
+	if value == "" {
+		return "open", nil
+	}
+	switch value {
+	case "open", "closed", "all":
+		return value, nil
+	default:
+		return "", fmt.Errorf("invalid state %q: use open, closed, or all", value)
+	}
